import React, { useState } from "react"
import makeStyles from "@mui/styles/makeStyles"
import List from "@mui/material/List"
import ListItem from "@mui/material/ListItem"
import ListItemText from "@mui/material/ListItemText"
import DeletedIcon from "@mui/icons-material/Delete"
import preset from "../../datasheet/screen_preset.yml"
import { useSelector, useDispatch } from "react-redux"
import { deleteDevice, loadDevice, loadPreset } from "../../state/displaySlice"
import {
  Box,
  IconButton,
  ListItemSecondaryAction,
  ListSubheader,
  Snackbar,
} from "@mui/material"
import CloseIcon from "@mui/icons-material/Close"

const useStyles = makeStyles(theme => ({
  root: {
    width: "100%",
    // maxWidth: 360,
    backgroundColor: theme.palette.background.paper,
  },
}))

const Device = ({
  size,
  name = "Screen",
  width,
  height,
  slot = 0,
  dispatch,
  preset = false,
  clickCallback,
}) => {
  const action = preset ? loadPreset : loadDevice
  return (
    <ListItem
      dense
      button
      onClick={e => {
        dispatch(action({ name, slot }))
        clickCallback(name)
      }}
    >
      <ListItemText
        primary={name + (slot || "")}
        secondary={`${size}', ${width}×${height}`}
      />
      {!preset && (
        <ListItemSecondaryAction>
          <IconButton
            edge="end"
            aria-label="delete"
            onClick={e => {
              dispatch(deleteDevice({ name, slot }))
            }}
            children={<DeletedIcon />}
            size="large"
          />
        </ListItemSecondaryAction>
      )}
    </ListItem>
  )
}

export default function FolderList() {
  const classes = useStyles()
  const dispatch = useDispatch()
  const deviceList = useSelector(state => state.display.deviceList)
  const [loadOpen, setLoadOpen] = useState(false)
  const [promptText, setPromptText] = useState("")
  const handleClose = e => {
    setLoadOpen(false)
  }
  const handleOpen = name => {
    setPromptText(name)
    setLoadOpen(true)
  }
  return (
    <Box height="100%" bgcolor="white" boxShadow="0 0 2rem #3333">
      <List
        className={classes.root}
        subheader={<ListSubheader component="div">Preset</ListSubheader>}
      >
        {preset.length ? (
          preset.map(data => {
            return (
              <Device
                key={`${data.name}-${data.slot}`}
                dispatch={dispatch}
                preset
                clickCallback={handleOpen}
                {...data}
              />
            )
          })
        ) : (
          <ListItem>
            <ListItemText primary="No data" />
          </ListItem>
        )}
      </List>
      <List
        className={classes.root}
        subheader={<ListSubheader component="div">Saved Devices</ListSubheader>}
      >
        {deviceList.length ? (
          deviceList.map(data => {
            return (
              <Device
                key={`${data.name}-${data.slot}`}
                dispatch={dispatch}
                clickCallback={handleOpen}
                {...data}
              />
            )
          })
        ) : (
          <ListItem>
            <ListItemText primary="No data" />
          </ListItem>
        )}
      </List>
      <Snackbar
        open={loadOpen}
        autoHideDuration={3000}
        onClose={handleClose}
        message={
          <>
            <strong>{promptText}</strong> loaded.
          </>
        }
        action={
          <IconButton
            size="small"
            aria-label="close"
            color="inherit"
            onClick={handleClose}
          >
            <CloseIcon fontSize="small" />
          </IconButton>
        }
      ></Snackbar>
    </Box>
  )
}
