import { Box, Tooltip } from "@mui/material"
import withStyles from "@mui/styles/withStyles"
import React from "react"
import AspectRatioIcon from "@mui/icons-material/AspectRatio"
import HeightIcon from "@mui/icons-material/Height"
import SettingsOverscanIcon from "@mui/icons-material/SettingsOverscan"
import FourKIcon from "@mui/icons-material/FourK"
import HdIcon from "@mui/icons-material/Hd"

const ScreenTooltipBase = withStyles(theme => {
  return {
    tooltip: {
      background: "#68c",
    },
  }
})(Tooltip)

const ScreenTooltip = ({ title, Icon }) => {
  return (
    <ScreenTooltipBase title={title}>
      <Icon style={{ margin: "0.3rem 0.5rem" }} />
    </ScreenTooltipBase>
  )
}

const ScreenUsecases = () => (
  <Box display="inline-flex" mx="auto" justifyContent="center" flexWrap="wrap">
    <ScreenTooltip title="Aspect Ratio" Icon={AspectRatioIcon} />
    <ScreenTooltip title="Scalable Distance" Icon={HeightIcon} />
    <ScreenTooltip title="Field of View (FOV)" Icon={SettingsOverscanIcon} />
    <ScreenTooltip title="Retina Detected" Icon={FourKIcon} />
    <ScreenTooltip title="Preset Size" Icon={HdIcon} />
  </Box>
)

export default ScreenUsecases
