import React, { useState } from "react"
import {
  Box,
  Slider,
  InputLabel,
  InputAdornment,
  Input,
  FormControl,
  Tooltip,
} from "@mui/material"
import HelpIcon from "@mui/icons-material/Help"
// import "../css/screen.css"

import { useSelector } from "react-redux"
import { map } from "lodash"
import screenSiteData from "../../datasheet/screen_site.yml"

const { Properties } = screenSiteData

const DescriptionList = ({ title = "Specification", data = {} }) => {
  return (
    <Box
      display="block"
      m={2}
      p={2}
      bgcolor="white"
      border="solid 1px #3333"
      minWidth="230px"
    >
      <span className="screen-dl-title">{title}</span>
      <dl className="screen-dl">
        {map(data, (value, key) => {
          return (
            <React.Fragment key={title + key}>
              <dt>
                {key}
                {Properties[key] && (
                  <Tooltip title={Properties[key]} children={<HelpIcon />} />
                )}
              </dt>
              <dd>{value}</dd>
            </React.Fragment>
          )
        })}
      </dl>
    </Box>
  )
}

const ViewDistanceWidget = ({ distance, setDistance }) => {
  const handleClick = e => e?.target?.select && e.target.select()
  return (
    <Box
      display="inline-block"
      bgcolor="white"
      py={3}
      p={2}
      m={2}
      border="solid 1px #3333"
      maxWidth="12rem"
      // mr="auto"
    >
      <FormControl fullWidth>
        <InputLabel htmlFor="view-distance">View Distance</InputLabel>
        <Input
          id="view-distance"
          type="number"
          value={distance}
          onClick={handleClick}
          onChange={e => setDistance(e.target.value)}
          endAdornment={<InputAdornment position="end">cm</InputAdornment>}
        />
      </FormControl>
      <Slider
        value={distance > 250 ? 250 : distance}
        onChange={(e, value) => setDistance(Number(value))}
        valueLabelDisplay="auto"
        max={250}
      />
    </Box>
  )
}

const ScreenBlock = function () {
  const width = useSelector(state => state.display.width)
  const height = useSelector(state => state.display.height)
  const size = useSelector(state => state.display.size)
  const name = useSelector(state => state.display.name)
  const asp = useSelector(state => state.display.aspect)
  const curvature = useSelector(state => {
    return state.display.curvature.use ? state.display.curvature.r : 0
  })
  const [distance, setDistance] = useState(150)
  // const [curvature, setCurvature] = useState(1500)

  const dpi = (width ** 2 + height ** 2) ** 0.5 / size
  const calR = curvature ? curvature : 99999999
  const ppd = 0.006872 * distance * dpi
  const retina_distance = 60 / dpi / 0.006872
  const phy_width = (width / dpi) * 2.54
  const phy_height = (height / dpi) * 2.54
  const d = (90 / ((Math.PI * calR) / 10)) * phy_width
  const x_offset = ((1 - Math.cos((d * Math.PI) / 180)) * calR) / 10
  const y_offset = (Math.sin((d * Math.PI) / 180) * calR) / 10
  const promoted_width =
    distance - x_offset > 0
      ? ((2 * y_offset) / (distance - x_offset)) * distance
      : Infinity
  const FOV = (Math.atan(promoted_width / 2 / distance) * 180) / Math.PI
  // const promoted_width = 2 * (Math.tan(d * Math.PI / 180)) * distance
  const screen_size_ratio = (500 + Math.log(size) * 50) / (asp.w + asp.h)
  const screen_style = {
    width: `${asp.w * screen_size_ratio}px`,
    height: `${asp.h * screen_size_ratio}px`,
    maxWidth: "calc(100vw - 6rem)",
    maxHeight: `calc(calc(100vw - 6rem) * ${Number(asp.h / asp.w).toFixed(2)})`,
  }
  return (
    <Box width="100%" mb={3}>
      <Box {...screen_style} className="screen-area">
        <div className="size-tag">
          {size} <small>inch</small>
        </div>
        <div className="dpi-tag">{dpi.toFixed(0)} PPI</div>
        <div className="screen-name">{name}</div>
        <div className="bottom-desc">{width} px</div>
        <div className="bottom-desc outside">
          {((width / dpi) * 2.54).toFixed(2)} cm
        </div>
        <div className="right-desc">{height} px</div>
        <div className="right-desc outside">
          {((height / dpi) * 2.54).toFixed(2)} cm
        </div>
      </Box>
      <Box
        display="flex"
        // width="100%"
        flexWrap="wrap"
        justifyContent="center"
        alignItems="flex-start"
      >
        <ViewDistanceWidget {...{ distance, setDistance }} />
        <DescriptionList
          title="Resolution"
          data={{
            Horizontal: `${width} px`,
            Vertical: `${height} px`,
            "Aspect Ratio": `${asp.w}:${asp.h}`,
            "Total Pixels": `${(width * height).toLocaleString()}`,
          }}
        />
        <DescriptionList
          title="Physic status"
          data={{
            "Diagonal Length": `${size}' (${(size * 2.54).toFixed(2)} cm)`,
            Width: `${phy_width.toFixed(2)} cm`,
            Height: `${phy_height.toFixed(2)} cm`,
            "Screen area": `${(phy_width * phy_height).toFixed(2)} cm²`,
            "Pixel per Inch(PPI, DPI)": `${dpi.toFixed(2)}`,
          }}
        />
        <DescriptionList
          title="View Properties"
          data={{
            "Pixel per degree (PPD)": `${ppd.toFixed(2)} px`,
            "Field of view (FOV)": `${(FOV * 2).toFixed(2)}°`,
            "Promoted width": `${promoted_width.toFixed(2)} cm`,
            "Become retina display": `Far than ${retina_distance.toFixed(
              2
            )} cm`,
          }}
        />
      </Box>
    </Box>
  )
}

export default ScreenBlock
